import { ApplicationConfig } from '@angular/core';
import { provideRouter, withComponentInputBinding, withViewTransitions } from '@angular/router';
import { provideHttpClient } from '@angular/common/http';
import { routes } from './app.routes';

export const appConfig: ApplicationConfig = {
  providers: [
    provideRouter(
      routes,

      // Automatically binds route params/query/data to component @input() signals
      // e.g. route { path: 'user/:id' } → component input() id will receive the value
      withComponentInputBinding(),

      // Smooth CSS View Transitions API between route navigations
      withViewTransitions(),
    ),

    provideHttpClient(),
  ],
};

import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';

export const routes: Routes = [

  // ① Static route — component loaded eagerly
  {
    path: '',
    loadComponent: () =>
      import('./features/home/home.component').then(m => m.HomeComponent),
    title: 'Home',   // sets the browser tab title
  },

  // ② Route with URL parameter (:id)
  {
    path: 'user/:id',
    loadComponent: () =>
      import('./features/user/user.component').then(m => m.UserComponent),
    title: 'User Profile',
  },

  // ③ Nested routes — ShellComponent renders children via its own <router-outlet>
  {
    path: 'dashboard',
    loadComponent: () =>
      import('./features/shell/shell.component').then(m => m.ShellComponent),
    canActivate: [authGuard],   // guard: only logged-in users
    children: [
      { path: '',        redirectTo: 'overview', pathMatch: 'full' },
      { path: 'overview',  loadComponent: () => import('./features/overview/overview.component').then(m => m.OverviewComponent) },
      { path: 'settings',  loadComponent: () => import('./features/settings/settings.component').then(m => m.SettingsComponent) },
    ],
  },

  // ④ Redirect
  { path: 'home', redirectTo: '', pathMatch: 'full' },

  // ⑤ 404 — catch-all wildcard (must be LAST)
  {
    path: '**',
    loadComponent: () =>
      import('./features/not-found/not-found.component').then(m => m.NotFoundComponent),
    title: '404 Not Found',
  },
];

