import { Component, input, computed, inject, effect } from '@angular/core';
import { RouterLink } from '@angular/router';
import { ProductService } from './product.service';

// Route definition: { path: 'product/:id', loadComponent: ... }

@Component({
  selector: 'app-product',
  standalone: true,
  imports: [RouterLink],
  template: `
    @if (product(); as p) {
      <nav>
        <a routerLink="/products">← Products</a>
        <span>/ {{ p.name }}</span>
      </nav>
      <h1>{{ p.name }}</h1>
      <p>{{ p.description }}</p>
      <p>Price: {{ p.price | currency }}</p>
    } @else if (loading()) {
      <p>Loading product {{ id() }}...</p>
    } @else {
      <p>Product not found.</p>
    }

    <!-- Query params are also received as inputs -->
    @if (tab()) {
      <p>Active tab: {{ tab() }}</p>
    }
  `,
})
export class ProductComponent {
  // ① Route param :id → received automatically as input
  //    withComponentInputBinding() in app.config wires this up
  id = input.required<string>();

  // ② Query param ?tab=reviews → also received as input
  tab = input<string>();

  private productService = inject(ProductService);

  loading = this.productService.loading;
  product = computed(() =>
    this.productService.getById(+this.id())  // +id() converts string → number
  );

  constructor() {
    // effect() re-runs whenever id() changes (user navigates to different product)
    effect(() => {
      this.productService.load(+this.id());
    });
  }
}

// URLs that will work:
// /product/1          → id()='1'
// /product/42?tab=reviews  → id()='42', tab()='reviews'

