// ── Guard with role check ─────────────────────────────────
export const adminGuard: CanActivateFn = () => {
  const auth   = inject(AuthService);
  const router = inject(Router);

  if (auth.hasRole('admin')) return true;
  return router.createUrlTree(['/forbidden']);
};

// ── Unsaved changes guard ─────────────────────────────────
export const unsavedChangesGuard: CanDeactivateFn<{ hasUnsaved: () => boolean }> =
  (component) => {
    if (!component.hasUnsaved()) return true;
    return confirm('You have unsaved changes. Leave anyway?');
  };

import { Component, inject, signal } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AuthService } from './auth.service';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [FormsModule],
  template: `
    <form (submit)="onSubmit($event)">
      <input [(ngModel)]="email"    name="email"    type="email" />
      <input [(ngModel)]="password" name="password" type="password" />
      <button [disabled]="loading()" type="submit">
        {{ loading() ? 'Signing in...' : 'Sign In' }}
      </button>
      @if (error()) { <p class="error">{{ error() }}</p> }
    </form>
  `,
})
export class LoginComponent {
  private auth    = inject(AuthService);
  private router  = inject(Router);
  private route   = inject(ActivatedRoute);   // to read ?returnUrl=

  email    = '';
  password = '';
  loading  = signal(false);
  error    = signal('');

  async onSubmit(e: Event): Promise<void> {
    e.preventDefault();
    this.loading.set(true);
    this.error.set('');

    try {
      await this.auth.login(this.email, this.password);

      // Read the returnUrl from the query string (set by authGuard)
      const returnUrl = this.route.snapshot.queryParams['returnUrl'] || '/dashboard';

      // Navigate after login — replaceUrl so back button skips login page
      await this.router.navigateByUrl(returnUrl, { replaceUrl: true });

    } catch (err) {
      this.error.set('Invalid email or password');
      this.loading.set(false);
    }
  }

  // ── Other navigate() patterns ─────────────────────────────
  goToProfile(id: number): void {
    this.router.navigate(['/user', id]);
  }

  goToSearch(query: string): void {
    this.router.navigate(['/search'], { queryParams: { q: query } });
  }

  // Relative navigation (from /dashboard → /dashboard/settings)
  goToSettings(): void {
    this.router.navigate(['settings'], { relativeTo: this.route });
  }
}

